INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('招聘专员 - 北京（校招）', '人力资源服务 / 咨询', '北京', '上市公司', 6000, 12000, '1. 熟练操作主流招聘渠道，掌握招聘全流程操作规范；2. 掌握候选人 mapping 寻访技能，可独立完成 mapping 报告撰写；3. 具备招聘目标拆解与数据分析能力，可基于数据输出优化解法；4. 熟悉校招、内推等招聘专项项目的全流程运营逻辑；5. 具备清晰的书面与口头表达能力，可独立完成候选人沟通、邀约与共识达成', '1. 结果导向，目标感强，可独立完成招聘交付目标；2. 具备独立解决复杂 / 困难问题的能力，可从过往经历中沉淀可复用的方法论；3. 沟通表达与逻辑思维能力强，可主动引导沟通并达成共识；4. 学习能力强，可快速适配招聘项目的运营节奏；5. 具备较强的抗压能力，可接受结果导向的工作模式', 1, '友好', '1. 支持业务线招聘，熟练掌握招聘渠道使用、流程等操作；2. 结果导向，完成候选人寻访及邀约目标、mapping 报告等交付目标；3. 参与业务线招聘相关重点项目运营，如内推、校招、交付攻坚等。', '招聘全流程执行, 候选人寻访 /mapping, 招聘数据分析, 校招项目运营, 渠道拓展与运营', '本科及以上', '无明确限制（有招聘相关实习经验者优先）', '0.5-5 年招聘相关经验，25/26 届学历潜力优秀应届生可放宽，有行业经验、乙方猎头、大厂实习、外包、甲方招聘交付经验优先', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先、英语能力优秀优先', '6k-12k / 月', '46078', '46173', 'https://www.shixiseng.com/intern/inn_nehizpvg6qeq?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('招聘专员 - 成都（校招）', '互联网 / IT', '成都', '民营企业', 4000, 8000, '1. 熟练使用 Word/Excel/PPT 等办公软件，可独立完成招聘数据统计与表格整理；2. 熟练操作 BOSS 直聘、脉脉、猎聘等主流招聘渠道，掌握候选人搜寻方法；3. 掌握招聘全流程操作规范，可独立完成简历筛选、初步面试评估、面试跟进全流程；4. 具备基础的候选人匹配度评估能力，可精准识别岗位与候选人的匹配点；5. 熟练使用各类 AI 工具，可借助 AI 完成招聘相关的基础工作。', '1. 具备优秀的沟通表达能力，亲和力强，有良好的服务意识和耐心；2. 执行力强，注重细节，可高效处理多线程工作任务；3. 对人力资源招聘工作有浓厚兴趣，愿意长期在该领域发展；4. 学习能力强，可快速掌握招聘相关的流程与工具；5. 工作严谨负责，有良好的时间管理与进度跟进能力。', 1, '极度友好', '1. 完成岗位的招聘全流程，包括职位发布、简历筛选、电话沟通、面试安排等；2. 使用招聘渠道（如 BOSS 直聘、脉脉、猎聘等）主动搜寻候选人，初步评估匹配度；3. 维护招聘渠道，更新候选人跟踪表，确保信息准确；4. 与潜在候选人进行初步电话 / 微信沟通，介绍公司及岗位信息；5. 协调面试时间，跟进面试进度，提升候选人体验。', '招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 候选人寻访 /mapping', '本科及以上', '人力资源管理、心理学、管理学等相关专业优先', '无强制全职经验要求，25/26届应届生（毕业1年内）可投，有招聘相关实习经验优先', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先、心理学相关专业背景优先', '4k-8k / 月', '46077', '46108', 'https://www.shixiseng.com/intern/inn_ev3kzx3ugh6o?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('HR 招聘实习生 - 北京（留用实习）', '互联网 / IT', '北京', '上市公司', 5000, 10000, '1. 掌握招聘全流程操作规范，可独立完成需求分析到入职跟进的全闭环工作；2. 具备招聘策略制定与落地能力，可基于业务需求匹配对应招聘方案；3. 具备招聘全流程数据分析能力，可通过数据优化招聘流程与策略；4. 具备人才地图 mapping 与行业人才洞察能力，可独立完成定向人才挖掘；5. 了解新兴招聘模式与工具，可探索落地创新招聘方式。', '1. 具备极强的学习能力，可快速理解互联网行业业务逻辑与岗位需求；2. 结果导向，目标感强，可独立推进招聘项目落地完成交付目标；3. 具备优秀的沟通协调能力，可高效对接业务端与候选人；4. 具备创新意识与问题解决能力，可主动优化招聘流程与模式；5. 对人力资源招聘工作有浓厚兴趣，愿意长期在该领域深耕。', 1, '友好', '1. 招聘策略制定：基于公司核心业务战略，深入洞察业务需求，制定并执行高效的招聘策略，确保关键岗位人才供给；2. 全流程招聘管理：负责招聘全流程，包括需求分析、渠道拓展、候选人筛选、深入评估、Offer 谈判及入职跟进，提升招聘效率与候选人体验；3. 数据驱动招聘优化：分析招聘全流程数据（如转化率、招聘周期等），通过数据监控与分析持续优化招聘流程与工具；4. 市场与人才洞察：收集并分析行业人才动态，搭建人才地图，输出前瞻性的人才规划与招聘策略；5. 创新招聘模式：探索并实践新兴招聘方式（如 AI 招聘、社交媒体招聘、人才社区运营等），提升招聘效果与雇主品牌影响力。', '招聘全流程执行, 渠道拓展与运营, 招聘数据分析, 招聘流程优化, 招聘制度与体系搭建', '本科及以上', '无明确限制，人力资源管理相关专业优先', '无强制全职经验要求，在校本科生可投，有招聘相关实习经验优先', '日常实习', '人力资源管理师相关证书优先、有互联网大厂招聘实习经验优先、有校园招聘项目运营经验优先', '薪资面议', '46105', '46190', 'https://www.shixiseng.com/intern/inn_0mdav37nizgp?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘实习生 - 珠海', '人力资源服务 / 咨询', '珠海', '国企 / 央企', 5000, 10000, '1. 熟练掌握招聘全流程基础操作，可独立完成简历筛选、面试邀约等基础工作；2. 可熟练使用办公软件，完成招聘相关的基础文档整理、数据统计工作；3. 具备基础的候选人匹配度评估能力，可精准识别简历与岗位的匹配点。', '1. 具备严谨负责的工作态度，良好的沟通协调能力、较强的执行力与团队协作意识；2. 学习能力强，可快速掌握招聘流程与工作方法；3. 责任心强，可保证实习的连续性与到岗率；4. 亲和力强，有良好的服务意识，可高效完成候选人沟通对接。', 1, '极度友好', '1. 协助开展招聘全流程工作，包括简历筛选、面试邀约、面试组织及后续跟进等相关事宜；2. 配合完成人力资源相关辅助工作，具体工作内容根据部门实际需求统筹安排', '招聘全流程执行, 简历筛选与面试', '本科及以上', '无明确限制，人力资源管理相关专业优先', '在校学生均可投递，需保证实习 2 个月及以上，每周全勤到岗 5 天', '日常实习', '人力资源管理师相关证书优先、有招聘相关实习经验优先', '薪资面议', '46106', '46160', 'https://www.shixiseng.com/intern/inn_flbgtcoszsoa?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('招聘实习生 - 西安', '教育 / 培训', '西安', '民营企业', 120, 150, '1. 熟练操作主流招聘渠道，可独立完成招聘信息发布与更新；2. 掌握简历筛选与面试邀约技能，可独立完成候选人初步沟通与面试安排；3. 可熟练使用办公软件，完成面试档案整理、招聘数据统计等基础工作；4. 具备基础的招聘数据整理与分析能力。', '1. 责任心强，做事严谨、细心，认真负责；2. 具备良好的沟通能力与应变能力，可高效完成候选人对接；3. 学习能力强，可快速掌握招聘全流程操作规范；4. 抗压能力强，可适应多线程工作节奏。', 1, '友好', '1. 根据招聘需求，在招聘渠道发布及更新招聘信息；2. 